2809 /// Match UB-safe variants of the funnel shift intrinsic.
2810 static Instruction *matchFunnelShift(Instruction &Or, InstCombinerImpl &IC,
2811                                      const DominatorTree &DT) {
2812   // TODO: Can we reduce the code duplication between this and the related
2813   // rotate matching code under visitSelect and visitTrunc?
2814   unsigned Width = Or.getType()->getScalarSizeInBits();
2815 
2816   Instruction *Or0, *Or1;
2817   if (!match(Or.getOperand(0), m_Instruction(Or0)) ||
2818       !match(Or.getOperand(1), m_Instruction(Or1)))
2819     return nullptr;
2820 
2821   bool IsFshl = true; // Sub on LSHR.
2822   SmallVector<Value *, 3> FShiftArgs;
2823 
2824   // First, find an or'd pair of opposite shifts:
2825   // or (lshr ShVal0, ShAmt0), (shl ShVal1, ShAmt1)
2826   if (isa<BinaryOperator>(Or0) && isa<BinaryOperator>(Or1)) {
2827     Value *ShVal0, *ShVal1, *ShAmt0, *ShAmt1;
2828     if (!match(Or0,
2829                m_OneUse(m_LogicalShift(m_Value(ShVal0), m_Value(ShAmt0)))) ||
2830         !match(Or1,
2831                m_OneUse(m_LogicalShift(m_Value(ShVal1), m_Value(ShAmt1)))) ||
2832         Or0->getOpcode() == Or1->getOpcode())
2833       return nullptr;
2834 
2835     // Canonicalize to or(shl(ShVal0, ShAmt0), lshr(ShVal1, ShAmt1)).
2836     if (Or0->getOpcode() == BinaryOperator::LShr) {
2837       std::swap(Or0, Or1);
2838       std::swap(ShVal0, ShVal1);
2839       std::swap(ShAmt0, ShAmt1);
2840     }
2841     assert(Or0->getOpcode() == BinaryOperator::Shl &&
2842            Or1->getOpcode() == BinaryOperator::LShr &&
2843            "Illegal or(shift,shift) pair");
2844 
2845     // Match the shift amount operands for a funnel shift pattern. This always
2846     // matches a subtraction on the R operand.
2847     auto matchShiftAmount = [&](Value *L, Value *R, unsigned Width) -> Value * {
2848       // Check for constant shift amounts that sum to the bitwidth.
2849       const APInt *LI, *RI;
2850       if (match(L, m_APIntAllowUndef(LI)) && match(R, m_APIntAllowUndef(RI)))
2851         if (LI->ult(Width) && RI->ult(Width) && (*LI + *RI) == Width)
2852           return ConstantInt::get(L->getType(), *LI);
2853 
2854       Constant *LC, *RC;
2855       if (match(L, m_Constant(LC)) && match(R, m_Constant(RC)) &&
2856           match(L,
2857                 m_SpecificInt_ICMP(ICmpInst::ICMP_ULT, APInt(Width, Width))) &&
2858           match(R,
2859                 m_SpecificInt_ICMP(ICmpInst::ICMP_ULT, APInt(Width, Width))) &&
2860           match(ConstantExpr::getAdd(LC, RC), m_SpecificIntAllowUndef(Width)))
2861         return ConstantExpr::mergeUndefsWith(LC, RC);
2862 
2863       // (shl ShVal, X) | (lshr ShVal, (Width - x)) iff X < Width.
2864       // We limit this to X < Width in case the backend re-expands the
2865       // intrinsic, and has to reintroduce a shift modulo operation (InstCombine
2866       // might remove it after this fold). This still doesn't guarantee that the
2867       // final codegen will match this original pattern.
2868       if (match(R, m_OneUse(m_Sub(m_SpecificInt(Width), m_Specific(L))))) {
2869         KnownBits KnownL = IC.computeKnownBits(L, /*Depth*/ 0, &Or);
2870         return KnownL.getMaxValue().ult(Width) ? L : nullptr;
2871       }
2872 
2873       // For non-constant cases, the following patterns currently only work for
2874       // rotation patterns.
2875       // TODO: Add general funnel-shift compatible patterns.
2876       if (ShVal0 != ShVal1)
2877         return nullptr;
2878 
2879       // For non-constant cases we don't support non-pow2 shift masks.
2880       // TODO: Is it worth matching urem as well?
2881       if (!isPowerOf2_32(Width))
2882         return nullptr;
2883 
2884       // The shift amount may be masked with negation:
2885       // (shl ShVal, (X & (Width - 1))) | (lshr ShVal, ((-X) & (Width - 1)))
2886       Value *X;
2887       unsigned Mask = Width - 1;
2888       if (match(L, m_And(m_Value(X), m_SpecificInt(Mask))) &&
2889           match(R, m_And(m_Neg(m_Specific(X)), m_SpecificInt(Mask))))
2890         return X;
2891 
2892       // (shl ShVal, X) | (lshr ShVal, ((-X) & (Width - 1)))
2893       if (match(R, m_And(m_Neg(m_Specific(L)), m_SpecificInt(Mask))))
2894         return L;
2895 
2896       // Similar to above, but the shift amount may be extended after masking,
2897       // so return the extended value as the parameter for the intrinsic.
2898       if (match(L, m_ZExt(m_And(m_Value(X), m_SpecificInt(Mask)))) &&
2899           match(R,
2900                 m_And(m_Neg(m_ZExt(m_And(m_Specific(X), m_SpecificInt(Mask)))),
2901                       m_SpecificInt(Mask))))
2902         return L;
2903 
2904       if (match(L, m_ZExt(m_And(m_Value(X), m_SpecificInt(Mask)))) &&
2905           match(R, m_ZExt(m_And(m_Neg(m_Specific(X)), m_SpecificInt(Mask)))))
2906         return L;
2907 
2908       return nullptr;
2909     };
2910 
2911     Value *ShAmt = matchShiftAmount(ShAmt0, ShAmt1, Width);
2912     if (!ShAmt) {
2913       ShAmt = matchShiftAmount(ShAmt1, ShAmt0, Width);
